  const name = r['Lead Name'] || r.leadName || '';
  const email = r.Email || r.email || '';
  const website = r.Website || r.website || '';

  if (status === 'new' && name && email) {
    newLeads.push({
      json: {
        leadName: name,
        company: r.Company || r.company || '',
        website: website,
        role: r['Role/Title'] || r.role || r.title || '',
        email: email,
        linkedinUrl: r['LinkedIn URL'] || r.linkedinUrl || '',
        rowNumber: i + 2
      }
    });
  }
}

if (newLeads.length === 0) {
  return [{ json: { hasNewLeads: false } }];
}

return newLeads;

const lead = $json;
let research = { companyInfo: '', scrapedSuccessfully: false };

if (!lead.website) {
  research.companyInfo = `${lead.company} — no website provided. Role: ${lead.role}.`;
  return { json: { ...lead, research } };
}

try {
  let url = lead.website;
  if (!url.startsWith('http')) url = 'https://' + url;

  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: url,
    timeout: 15000,
    headers: { 'User-Agent': 'Mozilla/5.0 (compatible; research-bot)' },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });

  if (response && response.body) {
    let html = typeof response.body === 'string' ? response.body : JSON.stringify(response.body);

    const titleMatch = html.match(/<title[^>]*>(.*?)<\/title>/i);
    const title = titleMatch ? titleMatch[1].trim() : '';

    const metaMatch = html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']*)["']/i);
    const metaDesc = metaMatch ? metaMatch[1].trim() : '';

    html = html.replace(/<script[\s\S]*?<\/script>/gi, ' ');
    html = html.replace(/<style[\s\S]*?<\/style>/gi, ' ');
    html = html.replace(/<nav[\s\S]*?<\/nav>/gi, ' ');
    html = html.replace(/<footer[\s\S]*?<\/footer>/gi, ' ');
    html = html.replace(/<[^>]+>/g, ' ');
    html = html.replace(/&nbsp;|&amp;|&lt;|&gt;/g, ' ');
    html = html.replace(/\s+/g, ' ').trim();

    research.companyInfo = `Title: ${title}\nDescription: ${metaDesc}\nContent: ${html.substring(0, 1500)}`;
    research.scrapedSuccessfully = true;
  }
} catch (e) {
  research.companyInfo = `Could not scrape ${lead.website}. Company: ${lead.company}, Role: ${lead.role}.`;
}

return { json: { ...lead, research } };

