const lead = $('📄 Build Dossier').item.json;
const raw = $json;
let score = {};

function tryParse(str) {
  if (typeof str !== 'string') return null;
  str = str.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  try { return JSON.parse(str); } catch(e) {
    const m = str.match(/\{[\s\S]*"totalScore"[\s\S]*\}/);
    if (m) try { return JSON.parse(m[0]); } catch(e2) {}
    return null;
  }
}

function dig(obj, d) {
  if (d > 5 || !obj || typeof obj !== 'object') return null;
  if (obj.totalScore !== undefined) return obj;
  for (const k of ['output','text','message','content','response','result','data','kwargs','lc_kwargs']) {
    if (obj[k]) {
      if (typeof obj[k] === 'string') { const r = tryParse(obj[k]); if (r) return r; }
      else { const r = dig(obj[k], d+1); if (r) return r; }
    }
  }
  for (const k of Object.keys(obj)) {
    if (typeof obj[k] === 'string' && obj[k].includes('totalScore')) {
      const r = tryParse(obj[k]); if (r) return r;
    } else if (typeof obj[k] === 'object' && obj[k]) {
      const r = dig(obj[k], d+1); if (r) return r;
    }
  }
  return null;
}

try {
  if (raw && raw.totalScore !== undefined) score = raw;
  else { const f = dig(raw, 0); if (f) score = f; }
  if (score.totalScore === undefined) {
    const p = tryParse(JSON.stringify(raw));
    if (p) score = p;
  }
} catch(e) {}

if (score.totalScore === undefined) {
  score = { totalScore: 50, recommendation: 'pursue', overallAssessment: 'AI parse failed — default score.', keyInsight: 'Review manually' };
}

return { json: {
  ...lead,
  score: score.totalScore,
  recommendation: score.recommendation || (score.totalScore >= 40 ? 'pursue' : 'skip'),
  keyInsight: score.keyInsight || '',
  overallAssessment: score.overallAssessment || '',
  shouldPursue: score.totalScore >= 40
}};

