    email1: { subject: `Quick question about ${lead.company}`, body: `Hi ${firstName},\n\nI noticed ${lead.company} and wanted to reach out.\n\nWould love to share something relevant to your work as ${lead.role}.\n\nWorth a quick chat?\n\nBest,\n${senderName}` },
    email2: { subject: `Thought of ${lead.company}`, body: `Hi ${firstName},\n\nI had another thought about how we might help ${lead.company}.\n\nWe recently helped a similar company solve a challenge you might relate to.\n\nWould it make sense to share the details?\n\nBest,\n${senderName}` },
