    personalizationUsed: ['company name only — AI parse failed']
  };
}

function formatEmailBody(rawBody) {
  if (!rawBody) return '';
  let body = rawBody;
  body = body.replace(/\\n/g, '\n');
  body = body.replace(/\\\\n/g, '\n');
  body = body.replace(/^Subject:.*?\n\n?/i, '');
  body = body.replace(/^Subject:.*?\n/i, '');
  body = body.replace(/\*\*/g, '');
  body = body.replace(/^#+\s/gm, '');
  body = body.replace(/\[YOUR NAME\]/gi, senderName);
  body = body.replace(/\[Your Name\]/g, senderName);
  body = body.replace(/YourName/g, senderName);
  body = body.replace(/\n\n?(Best|Cheers|Thanks|Thank you|Regards|Kind regards|Warm regards|Sincerely|Talk soon|All the best),?\s*\n\s*[A-Z][a-zA-Z]*(\s+[A-Z][a-zA-Z]*)?\s*(\n\n?(Best|Cheers|Thanks|Thank you|Regards|Kind regards|Warm regards|Sincerely|Talk soon|All the best),?\s*\n\s*(\[YOUR NAME\]|YourName|[A-Z][a-zA-Z]*(\s+[A-Z][a-zA-Z]*)?))?$/i, '');
  body = body.replace(/\n\n?(Best|Cheers|Thanks|Regards|Sincerely|Talk soon),?\s*$/i, '');
  body = body.trimEnd();
