  subject = subject.replace(/^(Re:\s*)+/i, 'Re: ');
  return subject.trim();
}

function toHTML(plainText) {
  let html = plainText.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\n\n/g, '</p><p>').replace(/\n/g, '<br>');
  return '<div style="font-family: Arial, sans-serif; font-size: 14px; color: #333; line-height: 1.6;"><p>' + html + '</p></div>';
}

const email1Subject = formatSubject(emails.email1.subject, 1);
const email1Body = formatEmailBody(emails.email1.body);
const email2Subject = formatSubject(emails.email2.subject || emails.email1.subject, 2);
const email2Body = formatEmailBody(emails.email2.body);
const email3Subject = formatSubject(emails.email3.subject || emails.email1.subject, 3);
