const lead = $('📬 Has Active Leads?').item.json;
const gmailResults = $input.all();

// ⚠️ REPLACE WITH YOUR GMAIL ADDRESS
const MY_GMAIL = (lead.myGmail || 'user@example.com').toLowerCase().trim();

function safeParseDate(val) {
  if (val === null || val === undefined || val === '') return null;
  const str = String(val).trim();
  if (!str || str === '0' || str === 'undefined' || str === 'null') return null;

  if (/^\d{10,13}$/.test(str)) {
    const num = parseInt(str, 10);
    const ms = str.length <= 10 ? num * 1000 : num;
    const d = new Date(ms);
    if (!isNaN(d.getTime()) && d.getFullYear() > 2000 && d.getFullYear() < 2100) return d;
  }

  try {
    const d1 = new Date(str);
    if (!isNaN(d1.getTime()) && d1.getFullYear() > 2000 && d1.getFullYear() < 2100) return d1;
  } catch(e) {}

  const num = Number(val);
  if (!isNaN(num) && num > 1+1234567890) {
    const ms = num > 1+1234567890 ? num : num * 1000;
    try {
      const d2 = new Date(ms);
      if (!isNaN(d2.getTime()) && d2.getFullYear() > 2000 && d2.getFullYear() < 2100) return d2;
    } catch(e) {}
  }

  return null;
}

function extractEmail(fromStr) {
  if (!fromStr) return '';
  const s = String(fromStr).toLowerCase().trim();
  const match = s.match(/<([^>]+)>/);
  if (match) return match[1].trim();
  if (s.includes('@')) return s.trim();
  return s;
}

const email1SentDate = safeParseDate(lead.email1SentDate);

if (!email1SentDate) {
  return [{ json: {
    hasReply: false, leadName: lead.leadName || '', email: lead.email || '',
    company: lead.company || '', currentStatus: lead.status || '',
    replyDate: '', replySubject: '', replySnippet: '',
    debug: 'Could not parse email1SentDate: ' + String(lead.email1SentDate)
  }}];
}

if (!gmailResults || gmailResults.length === 0) {
  return [{ json: {
    hasReply: false, leadName: lead.leadName || '', email: lead.email || '',
    company: lead.company || '', currentStatus: lead.status || '',
    replyDate: '', replySubject: '', replySnippet: ''
  }}];
}

const leadEmail = (lead.email || '').toLowerCase().trim();
let replyFound = false;
let replyDate = '';
let replySubject = '';
let replySnippet = '';

for (const msg of gmailResults) {
  const m = msg.json || {};

  const labels = m.labelIds || m.labels || [];
  const labelArr = Array.isArray(labels) ? labels : [String(labels)];
  const labelStr = labelArr.join(',').toUpperCase();
  if (labelStr.includes('SENT') && !labelStr.includes('INBOX')) continue;

  const fromRaw = m.from || m.From || m.sender || m.Sender || '';
  const senderEmail = extractEmail(fromRaw);

  if (senderEmail === MY_GMAIL) continue;
  if (!senderEmail.includes(leadEmail) && !leadEmail.includes(senderEmail)) continue;

  const msgDate = safeParseDate(m.internalDate)
    || safeParseDate(m.date)
    || safeParseDate(m.Date)
    || safeParseDate(m.receivedDate)
    || null;

  if (!msgDate) continue;
  if (msgDate <= email1SentDate) continue;

  if (extractEmail(fromRaw) === MY_GMAIL) continue;

  replyFound = true;
  replyDate = msgDate.toISOString();
  replySubject = m.subject || m.Subject || '(no subject)';
  replySnippet = (m.snippet || m.textPlain || m.text || m.body || '').toString().substring(0, 300);
  break;
}

return [{ json: {
  hasReply: replyFound, leadName: lead.leadName || '', email: lead.email || '',
  company: lead.company || '', currentStatus: lead.status || '',
  replyDate: replyDate, replySubject: replySubject, replySnippet: replySnippet
}}];

